#include <iostream>
#include <vector>
#include <algorithm>
using namespace std; 

int n, m;
vector<vector<int>> adj;
vector<bool> viz;

void dfs(int nod, vector<int>& comp) {
    viz[nod] = true;
    comp.push_back(nod);
    for(int vec : adj[nod]) {
        if (!viz[vec]) dfs(vec, comp);
    }
}

int main() {
    if (!(cin >> n >> m)) return 0;
    adj.resize(n + 1);
    viz.resize(n + 1, false);
    for(int i = 0; i < m; i++) {
        int u, v;
        cin >> u >> v;
        adj[u].push_back(v);
        adj[v].push_back(u);
    }
    vector<vector<int>> comps;
    for(int i = 1; i <= n; i++) {
        if (!viz[i]) {
            vector<int> comp;
            dfs(i, comp);
            sort(comp.begin(), comp.end());
            comps.push_back(comp);
        }
    }
    cout << comps.size() << "\n";
    for(auto& comp : comps) {
        for(int nod : comp) cout << nod << " ";
        cout << "\n";
    }
    return 0;
}
